# Private functions
  @fn viewedName()  @ 25
  @fn projectTempers()  @ 27
  @fn globalTempers()  @ 30
      -- Reading the global library lazily seeds it from the EDO catalogue (minus the
      -- synthetic 12EDO floor) the first time. Mirrors swingEditor's globalSwings.
